#include <stdio.h>
#include <stdlib.h>

int main() {
    ios:
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long cnt = 0; // number of insertions so far
        for (int i = 1; i <= N; ++i) {
            long long a; scanf("%lld", &a);
            if (a == i + cnt) cnt++;
        }
        printf("%lld\n", cnt);
    }
    return 0;
}

