import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        cnt = 0
        for i in range(1, N + 1):
            a = int(next(it))
            if a == i + cnt:
                cnt += 1
        out_lines.append(str(cnt))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

